func:
// Manual trigger: any incoming msg is ignored — the tick loop is driven
// by the recursive setTimeout established in the On Start handler.
return null;

initialize:
// FACIS tick scheduler — recursive setTimeout to honour speed-factor
// changes without a redeploy.
const intervalMinutes = Number(env.get('INTERVAL_MINUTES') || 1);
const minRealMs = Number(env.get('MIN_REAL_INTERVAL_MS') || 50);
const advanceMs = intervalMinutes * 60000;

function realIntervalMs() {
    const engine = flow.get('engine');
    const speed = (engine && engine.acceleration) ? engine.acceleration : 1;
    return Math.max(minRealMs, advanceMs / Math.max(0.001, speed));
}

function fireTick() {
    const engine = flow.get('engine');
    if (!engine || engine.state !== 'running') return;

    const prevIso = engine.simulation_time || new Date().toISOString();
    const nextMs = new Date(prevIso).getTime() + advanceMs;
    const nextIso = new Date(nextMs).toISOString();

    engine.simulation_time = nextIso;
    engine.tick_index = (engine.tick_index || 0) + 1;
    flow.set('engine', engine);

    node.send({
        payload: {
            type: 'sim.tick.trigger',
            tick_index: engine.tick_index,
            timestamp: nextIso,
            timestamp_ms: nextMs,
            base_seed: engine.seed,
            site_id: env.get('SITE_ID') || 'site-default',
            acceleration: engine.acceleration,
            mode: env.get('MODE') || 'normal'
        }
    });
}

function loop() {
    try { fireTick(); } catch (err) { node.error('tick error: ' + err.message); }
    const t = setTimeout(loop, realIntervalMs());
    flow.set('__tick_timer', t);
}

// Start the loop after a short delay so the engine has a chance to load
// its persisted state.
const initial = setTimeout(loop, 1000);
flow.set('__tick_timer', initial);
node.log('tick scheduler initialised: interval=' + intervalMinutes + 'min, advance=' + advanceMs + 'ms');

finalize:
const t = flow.get('__tick_timer');
if (t) {
    clearTimeout(t);
    flow.set('__tick_timer', null);
    node.log('tick scheduler stopped');
}
